        return uniffiRustCallAsync(
        callWithHandle { uniffiHandle ->
            UniffiLib.uniffi_rusaint_ffi_fn_method_chapelapplication_get_selected_semester(
                uniffiHandle,
                
            )
        },
        { future, callback, continuation -> UniffiLib.ffi_rusaint_ffi_rust_future_poll_rust_buffer(future, callback, continuation) },
        { future, continuation -> UniffiLib.ffi_rusaint_ffi_rust_future_complete_rust_buffer(future, continuation) },
        { future -> UniffiLib.ffi_rusaint_ffi_rust_future_free_rust_buffer(future) },
        // lift function
