public object FfiConverterTypeUSaintSessionBuilder: FfiConverter<USaintSessionBuilder, Long> {
    override fun lower(value: USaintSessionBuilder): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): USaintSessionBuilder {
        return USaintSessionBuilder(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): USaintSessionBuilder {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: USaintSessionBuilder) = 8UL

    override fun write(value: USaintSessionBuilder, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



